window.__QUIZ_DATA__=[{"id":"theory>Geography>2017>Theory 1>1>a>i","subject":"Geography","year":"2017","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"In three ways, explain how each of the following factors has affected world population:    advanced technology;","images":[],"marking_scheme":"- Increased agricultural research   - Development of chemicals to control pests   - Early maturing and high yielding crops","marks":"8","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>1>a>ii","subject":"Geography","year":"2017","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"In three ways, explain how each of the following factors has affected world population:  improve medical care","images":[],"marking_scheme":"- Increased lifespan of people   - Adoption of family planning techniques   - Increase in birth rate","marks":"7","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>1>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight four factors which account for the high density of population in java","images":[],"marking_scheme":"- Political stability   - Immigration   - Improved medical care   - Government policies","marks":"5","difficulty":"3"},{"id":"theory>Geography>2017>Theory 1>2>a>i","subject":"Geography","year":"2017","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"State three functions each of the following settlements:    urban;","images":[],"marking_scheme":"- Mining function   - Educational function   - Religious function","marks":"8","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>2>a>ii","subject":"Geography","year":"2017","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"State three functions each of the following settlements:  rural","images":[],"marking_scheme":"- Residential function  - Local craft function   - Trading function","marks":"7","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>2>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline four areas of interdependence between rural and urban centres.","images":[],"marking_scheme":"- Housing   - Medical herbs   - Tourism and Recreational sites   - Food supply","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>3>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Explain five reasons why the production of consumer goods is common in developing countries.","images":[],"marking_scheme":"- It requires limited power supply   - High demand for consumer goods   - Low level of technology   - Need to conserve foreign exchange   - Inadequate skilled labour","marks":"10","difficulty":"3"},{"id":"theory>Geography>2017>Theory 1>3>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline five factors which influence industrial locations.","images":[],"marking_scheme":"- Government   - Presence of support service   - Availability of water   - Nearness to port facilities   - Political stability","marks":"10","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>4>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw a sketch map of Nigeria. locate and name:   (i) Owerri, Ibadan and Birnin Kebbi; (ii) Cross River and Fadama plains of River Sokoto.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2017>Theory 1>4>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"Outline four factors that encourage tourism in Nigeria","images":[],"marking_scheme":"- Availability of capital   - Improved transportation network   - Political stability   - Relative security","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>4>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"Highlight three problems hindering tourism in Nigeria.","images":[],"marking_scheme":"- Inadequate accommodation   - Low patronage   - Poor sanitation","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>5>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : MAP WORK","question":"Draw an outline map of Nigeria. On the map, mark and name:   (i)the railway line from Ibadan to Kano;  (ii) the main road from Port Harcourt to Lagos.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2017>Theory 1>5>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Highlight four contributions of transportation to the economic development of Nigeria.","images":[],"marking_scheme":"- Promotion of Tourism   - Promotion of Local Trade   - Infrastructural development   - Source of Income to workers","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>5>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Outline three problems limiting rail transportation in Nigeria","images":[],"marking_scheme":"- Inadequate skilled technicians   - Low level of technology   - Rugged road terrain","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>6>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Write a geographical account of Cross River plains under the following headings:    climate;","images":[],"marking_scheme":"Climate: It has a sub-equatorial climate which allows heavy rainfall throughout the year. It has a mean annual temperature of 21oC - 30oC from daily temperature ranges of 2oC - 3oC. It has cloudy skies, high relative humidity and possesses convectional rainfall.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2017>Theory 1>6>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Write a geographical account of Cross River plains under the following headings:   economic activities;","images":[],"marking_scheme":"They engage in farming, industrial activities, communication, fishing, trading, education, mining, lumbering, public service, tourism, etc.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2017>Theory 1>6>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Write a geographical account of Cross River plains under the following headings:   problems of development","images":[],"marking_scheme":"-Pollution   - Inadequate Infrastructure development   - Poor transportation system   - Dispersed settlements   - Incidence of soil erosion, leaching and pests.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>1>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the questions that follow.    using a vertical scale of 1cm to represent 200 feet, draw an annotated cross profile of the area marked A - B in the Southern part of the map.","images":["data:image/png;base64,"],"marking_scheme":"An annotated cross profile along line A - B.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>1>b>i","subject":"Geography","year":"2017","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Describe the influence of relief on: settlements in the mapped area","images":[],"marking_scheme":"- Few Isolated compounds area in the North-eastern part of the map because of the rugged relief   - Built-up settlements are found at the foot of the hills in the South east   - Ebiya is also located on a lowland between hills","marks":"3","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>1>b>ii","subject":"Geography","year":"2017","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Describe the influence of relef on: transportation network in the mapped area.","images":[],"marking_scheme":"- Because of the rugged terrain, only footpaths are found on the eastern mapped area  - The main roads is in the North West where there is gently rolling relief   - At the south, the secondary road avoids hills and ridges","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>1>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the drainage pattern of the mapped area?","images":[],"marking_scheme":"Dendritic drainage pattern","marks":"2","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>2>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Table 1 contains information on the traffic flow for the movement of passengers from Abuja International Airport to other airports in Nigeria in the year 2012.   Use it to calculate and construct a flowing chart for the movement of passengers into figure 1 on page 3, using a scale of 1 mm to represent 10,000 passengers.     Table 1: Traffic flow between Abuja international airport and other airports in Nigeria in the year 2012.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"A flowline Chart showing movement of Passenger for Abuja Airport to other Nigeria Airports in year 2012","marks":"15","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>2>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"List three advantages of flow charts.","images":[],"marking_scheme":"- They are attractive   - They are easy to understand   - They show relative importance of modes i.e cities","marks":"5","difficulty":"1"},{"id":"theory>Geography>2017>Theory 2>3>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"State the difference between erosion and mass movement","images":[],"marking_scheme":"Erosion is the washing away of the top soil due to water, wind, glacier or other natural means while Mass movement is a driven by the Gravitational force of the earth.","marks":"8","difficulty":"1"},{"id":"theory>Geography>2017>Theory 2>3>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"List four agents responsible for modifying landforms","images":[],"marking_scheme":"- Volcanism   - Earthquakes   - Force of gravitation/gravity","marks":"7","difficulty":"1"},{"id":"theory>Geography>2017>Theory 2>3>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Outline three factors that influences mass movement","images":[],"marking_scheme":"- Gravitational force   - Presence of vegetation   - Volcanic activities","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>4>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"List three characteristics of metamorphic rocks","images":[],"marking_scheme":"- They exist in various colours and textures   - They are not composed of mossils   - They evolve from previous or pre-existing igneous rocks or sedimentary rocks","marks":"8","difficulty":"1"},{"id":"theory>Geography>2017>Theory 2>4>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe three modes of formation of metamorphic rocks","images":[],"marking_scheme":"-  Thermo-dynamic metamorphism:   This form of metamorphism is gotten from combined heat and pressure on the pre-existing rocks.   -  Metasomation Metamorphism:   It is formed from chemically-active fluids   -  Regional or Dynamic Metamorphism:   It is formed from the action of high pressure on the pre-existing rocks.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>4>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Outline three economic benefits of rocks","images":[],"marking_scheme":"- Source of foreign exchange   - For tourism   - For construction and building purposes","marks":"5","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>5>a>i","subject":"Geography","year":"2017","type":"Theory","sub_label":"i","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of annotated diagram, describe the characteristics of the various stages of a river course.","images":["data:image/png;base64,"],"marking_scheme":"Upper Course:  This marks the source of a river. It is a steepslope which occurs in highland areas and is swift. Vertical erosion is dominant in this region and there are interlocking spurs, v-shaped valley, water falls, rapid cataracts, gorges, etc.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>5>a>ii","subject":"Geography","year":"2017","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of annotated diagram, describe the characteristics of the various stages of a river course.","images":[],"marking_scheme":"- Middle Course:It has U-shaped valleys, numerous interlocking spurs, river cliffs and bluffs. Lateral erosion is dominant as there is increased river load since the valleys are widened and slope gradient is more gentle than the upper course.","marks":"3","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>5>a>iii","subject":"Geography","year":"2017","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of annotated diagram, describe the characteristics of the various stages of a river course.","images":[],"marking_scheme":"Lower course: There is presence of pronounced meanders, wide flood plains, ox-bow lakes, leaves, gentle-sloping gradient and lateral erosion occurs. It is the end of the river course where deposition occurs (i.e sand bars and dunes are created)","marks":"2","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>5>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"List three ways by which rivers are beneficial","images":[],"marking_scheme":"- For fishing   - They create employment/jobs for people like fishing, naval jobs, etc.   - As source of mineral resources","marks":"5","difficulty":"1"},{"id":"theory>Geography>2017>Theory 2>6>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Draw an outline of the Earth and show the following:   (i) Equator; (ii) tropic of Cancer; (iii) Antarctic Circle","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>6>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Describe three characteristics of lines of longitude","images":[],"marking_scheme":"- It is the angular distance of a place East or West of the Greenwich Meridian.  - It is used in calculating local time   - It is used to locate places","marks":"3","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>6>c","subject":"Geography","year":"2017","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"A football match is scheduled for 5.45 pm local time on Saturday in Onisha, Nigeria (longitude 7oE). Calculate the local time football fans in Mambola, Sierra Leone (Longitude 13oW) can tune their radio sets for the commentary.","images":[],"marking_scheme":"Given;  - Onitsha, Nigeria 5:45pm Saturday (7oE long) Mambola, Sierra Leone, longitude   13oW, time = ?    Solution   Mambola is on longitude 13oW   Onitsha is on longitude 7oE   \u2234 Longitudinal difference = 13o + 7o = 20o     recall,   15o of longitude = 1hour   \u2234 Time difference between Onitsha and   Mambola = 20o x 1hr/15o = 1hr 20mins     12060hr=113hr    \u2234 Since Mambola is west of Onitsha,  \u2234 Mambola Time = 5:45pm - 1hr 20mins = 4:25pm on Saturday    \u2234 Football fans in Mambola Sierra Leone can their radio sets for the commentary at 4:25pm on Saturday.","marks":"7","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>7>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"List five sources of water pollution.","images":[],"marking_scheme":"- Flooding   - Acid rain   - Run off of fertilizers, pesticides and herbicides   - Disposal of untreated sewage   - Oil spillage","marks":"10","difficulty":"1"},{"id":"theory>Geography>2017>Theory 2>7>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Highlight five measures that can be taken to control water pollution.","images":[],"marking_scheme":"- Measures should be taken against the improper disposal of toxic wastes   - Good drainage system   - Use of good fishing methods   - Enforcement of legislations against the improper disposal of refuse and sewage  - Use of organic manure","marks":"10","difficulty":"2"},{"id":"theory>Geography>2017>Theory 2>8>a","subject":"Geography","year":"2017","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of diagrams, explain how the following factors affect the temperature of a place:    - latitude;","images":["data:image/png;base64,"],"marking_scheme":"Latitudes   Places that are near the poles are not as warm as those near the equator, since the sun is always high in the sky at the equator. Therefore, the heat generated from the vertical incidence of the sun on the earth's surface, is concentrated upon a smaller area, making it hot. Towards the poles, the sun rays travel a long distance, such that they lose their intensity","marks":"10","difficulty":"3"},{"id":"theory>Geography>2017>Theory 2>8>b","subject":"Geography","year":"2017","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of diagrams, explain how the following factors affect the temperature of a place:- Aspect and Slope","images":[],"marking_scheme":"The influence of slopes and aspect on temperature is seen in the temperate latitudes. In the northern hemisphere, South facing slopes receive more isolation than those of the north, making the south facing slopes warmer, while in the South Southern hemisphere, the reverse tis the case.   Therefore, slopes facing the sun receive more isolation than sheltered areas hence are warmer than sheltered areas which is why influence of slope on temperature is noticeable in mountainous areas.","marks":"10","difficulty":"3"}];